# --- HTML helper: evita o Streamlit tratar HTML indentado como bloco de código ---
def _html_block(s: str) -> str:
    s = textwrap.dedent(s)
    # remove indentação restante (>=4 espaços) para não virar code block no markdown
    s = re.sub(r'(?m)^[ \t]{4,}', '', s)
    return s.strip()


# --- HTML escape helper (para valores dinâmicos em unsafe_allow_html) ---
def _esc_html(v) -> str:
    return html.escape("" if v is None else str(v), quote=True)


# --- Export helper: converte DataFrame para Excel (.xlsx) ---
def _df_to_excel_bytes(df: pd.DataFrame, sheet_name: str = "Dados") -> bytes:
    output = BytesIO()
    df_export = pd.DataFrame() if df is None else df.copy()

    with pd.ExcelWriter(output, engine="openpyxl") as writer:
        df_export.to_excel(writer, index=False, sheet_name=sheet_name)
        ws = writer.sheets[sheet_name]
        ws.freeze_panes = "A2"

        for col_cells in ws.columns:
            try:
                col_letter = col_cells[0].column_letter
            except Exception:
                continue

            max_length = 0
            for cell in col_cells:
                try:
                    cell_value = "" if cell.value is None else str(cell.value)
                except Exception:
                    cell_value = ""
                max_length = max(max_length, len(cell_value))

            ws.column_dimensions[col_letter].width = min(max(max_length + 2, 12), 40)

    output.seek(0)
    return output.getvalue()


def _render_df_with_ctrc_links(
    df: pd.DataFrame,
    ctrc_col: str = "Serie/Numero CTRC",
    link_url: str = "https://sistema.ssw.inf.br/bin/ssw0053",
    max_rows: int | None = None,
):
    """Renderiza uma tabela HTML com a coluna de CTRC interativa.
    - Clique no prefixo (ex.: CGR) para abrir o SSW em nova aba.
    - Clique no número central (ex.: 387203) para copiar para a área de transferência.

    Observação: para o clique/copiar funcionar de forma confiável no Streamlit,
    a tabela é renderizada dentro de um componente HTML com JavaScript próprio.
    """
    if df is None or df.empty:
        st.dataframe(pd.DataFrame() if df is None else df, use_container_width=True, hide_index=True)
        return

    try:
        df_view = df.head(max_rows).copy() if max_rows else df.copy()
    except Exception:
        df_view = df.copy()

    df_html = df_view.copy()

    for col in df_html.columns:
        if col == ctrc_col:
            continue
        df_html[col] = df_html[col].apply(lambda v: _esc_html("" if pd.isna(v) else str(v)))

    if ctrc_col in df_view.columns:
        def _ctrc_to_actions(v):
            try:
                if pd.isna(v):
                    return "—"
            except Exception:
                pass

            txt = str(v).strip()
            if not txt or txt.upper() in {"NAN", "NONE"}:
                return "—"

            txt_compacto = re.sub(r"\s+", "", txt)
            m = re.match(r"^([A-Za-z]+)(\d+)(-[A-Za-z0-9]+)?$", txt_compacto)

            if not m:
                return (
                    f'<a href="{_esc_html(link_url)}" target="_blank" rel="noopener noreferrer" '
                    f'class="ctrc-link-cell" title="Abrir SSW">{_esc_html(txt)}</a>'
                )

            prefixo = m.group(1) or ""
            numero = m.group(2) or ""
            sufixo = m.group(3) or ""
            sufixo_exibicao = re.sub(r"^-(.+)$", r"- \1", sufixo)

            return (
                f'<div class="ctrc-actions-wrap">'
                f'  <button type="button" class="ctrc-prefix-btn" data-url="{_esc_html(link_url)}" '
                f'     title="Abrir SSW">{_esc_html(prefixo)}</button>'
                f'  <button type="button" class="ctrc-copy-btn" data-copy="{_esc_html(numero)}" '
                f'     title="Copiar número {_esc_html(numero)}">'
                f'     <span class="copy-label">{_esc_html(numero)}</span>'
                f'  </button>'
                f'  <span class="ctrc-suffix">{_esc_html(sufixo_exibicao)}</span>'
                f'</div>'
            )

        df_html[ctrc_col] = df_view[ctrc_col].apply(_ctrc_to_actions)

    st.caption(f"Clique em CGR para abrir o SSW e clique no número para copiar. Exibindo {len(df_view)} CTRCs da placa selecionada.")

    row_count = max(len(df_html.index), 1)
    _visible_rows = 12
    _row_px = 40
    _base_px = 120

    if row_count <= _visible_rows:
        comp_height = max(_base_px + row_count * _row_px, 220)
        _wrap_max_height = "none"
        _wrap_overflow_y = "visible"
    else:
        comp_height = min(max(_base_px + _visible_rows * _row_px, 520), 760)
        _wrap_max_height = f"{max(comp_height - 18, 480)}px"
        _wrap_overflow_y = "auto"

    html_table = df_html.to_html(index=False, escape=False, classes="ctrc-link-table", border=0)
    html_component = _html_block(
        f"""
        <style>
          html, body {{
            margin: 0;
            padding: 0;
            background: transparent;
            overflow: auto;
            font-family: Arial, Helvetica, sans-serif;
          }}
          .ctrc-link-table-wrap {{
            width: 100%;
            overflow-x: auto;
            overflow-y: {_wrap_overflow_y};
            max-height: {_wrap_max_height};
            border: 1px solid rgba(148,163,184,0.16);
            border-radius: 14px;
            background: rgba(2, 6, 23, 0.55);
            box-shadow: inset 0 1px 0 rgba(255,255,255,0.03);
          }}
          .ctrc-link-table-wrap::-webkit-scrollbar {{
            width: 10px;
            height: 10px;
          }}
          .ctrc-link-table-wrap::-webkit-scrollbar-thumb {{
            background: rgba(148,163,184,0.35);
            border-radius: 999px;
          }}
          .ctrc-link-table-wrap::-webkit-scrollbar-track {{
            background: rgba(15,23,42,0.35);
          }}
          table.ctrc-link-table {{
            width: 100%;
            min-width: 980px;
            border-collapse: collapse;
            font-size: 13px;
          }}
          table.ctrc-link-table thead th {{
            position: sticky;
            top: 0;
            z-index: 2;
            padding: 10px 12px;
            text-align: left;
            white-space: nowrap;
            background: rgba(8,15,30,0.98);
            color: #94a3b8;
            border-bottom: 1px solid rgba(148,163,184,0.18);
          }}
          table.ctrc-link-table tbody td {{
            padding: 10px 12px;
            white-space: nowrap;
            color: #e5e7eb;
            border-bottom: 1px solid rgba(148,163,184,0.10);
            vertical-align: middle;
          }}
          table.ctrc-link-table tbody tr:hover td {{
            background: rgba(59,130,246,0.06);
          }}
          .ctrc-link-cell {{
            color: #ffffff !important;
            font-weight: 700;
            text-decoration: none;
          }}
          .ctrc-link-cell:hover {{
            color: #f8fafc !important;
            text-decoration: underline;
          }}
          .ctrc-actions-wrap {{
            display: inline-flex;
            align-items: center;
            gap: 0;
          }}
          .ctrc-prefix-btn {{
            appearance: none;
            background: transparent;
            border: 0;
            color: #ffffff !important;
            font-weight: 800;
            text-decoration: none;
            padding: 0 2px 0 0;
            margin: 0;
            cursor: pointer;
            line-height: 1.1;
          }}
          .ctrc-prefix-btn:hover {{
            color: #ffffff !important;
            text-decoration: underline;
          }}
          .ctrc-copy-btn {{
            appearance: none;
            border: 1px solid rgba(147,197,253,0.28);
            background: rgba(59,130,246,0.10);
            color: #eaf2ff;
            font-weight: 700;
            border-radius: 8px;
            padding: 2px 6px;
            cursor: pointer;
            line-height: 1.2;
            margin: 0 -3px 0 0;
          }}
          .ctrc-copy-btn:hover {{
            background: rgba(59,130,246,0.18);
            border-color: rgba(147,197,253,0.42);
          }}
          .ctrc-suffix {{
            color: #cbd5e1;
            font-weight: 600;
            margin-left: -5px;
            letter-spacing: -0.1px;
          }}
        </style>
        <div class="ctrc-link-table-wrap">
          {html_table}
        </div>
        <script>
          (function() {{
            async function copyText(text) {{
              const value = (text || '').trim();
              if (!value) return false;

              try {{
                if (navigator.clipboard && window.isSecureContext) {{
                  await navigator.clipboard.writeText(value);
                  return true;
                }}
              }} catch (e) {{}}

              try {{
                const ta = document.createElement('textarea');
                ta.value = value;
                ta.setAttribute('readonly', 'readonly');
                ta.style.position = 'fixed';
                ta.style.left = '-9999px';
                ta.style.top = '0';
                document.body.appendChild(ta);
                ta.focus();
                ta.select();
                ta.setSelectionRange(0, ta.value.length);
                const ok = document.execCommand('copy');
                document.body.removeChild(ta);
                return ok;
              }} catch (e) {{
                return false;
              }}
            }}

            function markButton(btn, ok) {{
              const label = btn.querySelector('.copy-label');
              if (!label) return;
              const old = btn.getAttribute('data-old-label') || label.textContent;
              btn.setAttribute('data-old-label', old);
              label.textContent = ok ? 'Copiado' : 'Falhou';
              window.setTimeout(function() {{
                label.textContent = old;
              }}, 1200);
            }}

            document.querySelectorAll('.ctrc-prefix-btn').forEach(function(btn) {{
              btn.addEventListener('click', function(ev) {{
                ev.preventDefault();
                ev.stopPropagation();
                const url = btn.getAttribute('data-url') || '';
                if (url) window.open(url, '_blank', 'noopener,noreferrer');
              }});
            }});

            document.querySelectorAll('.ctrc-copy-btn').forEach(function(btn) {{
              btn.addEventListener('click', async function(ev) {{
                ev.preventDefault();
                ev.stopPropagation();
                const ok = await copyText(btn.getAttribute('data-copy') || '');
                markButton(btn, ok);
              }});
            }});
          }})();
        </script>
        """
    )

    components.html(html_component, height=comp_height, scrolling=True)



# =============================================================
# Helpers (coluna por aproximação / normalização) - usados no Ranking
# =============================================================
def _norm_key(s: str) -> str:
    s = "" if s is None else str(s)
    s = "".join(c for c in unicodedata.normalize("NFKD", s) if not unicodedata.combining(c))
    s = s.lower().strip()
    for ch in [" ", "_", "-", ".", "/", "\\", "(", ")", "[", "]"]:
        s = s.replace(ch, "")
    return s

def _find_col_contains(df: pd.DataFrame, *keywords: str):
    keys = [_norm_key(k) for k in keywords]
    for col in df.columns:
        c = _norm_key(col)
        if all(k in c for k in keys):
            return col
    return None

def _find_cubagem_col(df: pd.DataFrame):
    """Localiza a coluna de cubagem priorizando nomes exatos mais comuns.
    Ex.: 'Cubagem em m3', 'Cubagem em m³', 'Cubagem', 'M3'.
    """
    if df is None or getattr(df, 'empty', True):
        return None
    exact_aliases = [
        'Cubagem em m3', 'Cubagem em M3', 'Cubagem em m³', 'Cubagem em M³',
        'Cubagem m3', 'Cubagem M3', 'Cubagem (m3)', 'Cubagem (M3)',
        'Cubagem (m³)', 'Cubagem (M³)', 'Cubagem', 'M3', 'M³'
    ]
    norm_map = {_norm_key(col): col for col in df.columns}
    for alias in exact_aliases:
        found = norm_map.get(_norm_key(alias))
        if found:
            return found
    for keys in [
        ('cubagem', 'm3'),
        ('cubagem', 'm³'),
        ('cubagem',),
        ('cub', 'm3'),
        ('cub', 'm³'),
        ('cub',),
        ('m3',),
        ('m³',),
    ]:
        found = _find_col_contains(df, *keys)
        if found:
            return found
    return None

def _short_value(v, max_len: int = 12) -> str:
    s = "" if v is None else str(v)
    s = s.strip()
    return (s[:max_len] + "…") if len(s) > max_len else s

def _first_words(v, n: int = 2, max_len: int = None) -> str:
    """Retorna apenas os N primeiros 'nomes' (palavras) de uma string.
    Ex: 'ECOMEL COMERCIO E SERVICOS' -> 'ECOMEL COMERCIO'
    """
    s = "" if v is None else str(v)
    s = re.sub(r"\s+", " ", s.strip())
    if not s:
        return s
    parts = []
    for p in s.split(" "):
        pp = p.strip(" ,.;:|-_/\\")
        if pp:
            parts.append(pp)
    if not parts:
        return s
    out = " ".join(parts[: max(1, int(n))])
    if max_len is not None:
        out = _short_value(out, int(max_len))
    return out


def _first_name_tokens(v, n: int = 2, max_len: int = None) -> str:
    """Retorna os N primeiros blocos alfanuméricos de um texto.
    Ex: 'IMPORCATE COM.PCS.P/TRAT' -> 'IMPORCATE COM'
    Útil para cards de remetente onde '.', '/', '-' etc. não devem contar como parte do 'nome'.
    """
    s = "" if v is None else str(v)
    s = re.sub(r"\s+", " ", s.strip())
    if not s:
        return s
    parts = re.findall(r"[A-Za-zÀ-ÿ0-9]+", s)
    if not parts:
        return _first_words(s, n=n, max_len=max_len)
    out = " ".join(parts[: max(1, int(n))])
    if max_len is not None:
        out = _short_value(out, int(max_len))
    return out



# =============================================================
# Format helpers (pt-BR) — usados em várias abas (evita UnboundLocalError)
# =============================================================
def _fmt_int_pt(v):
    try:
        return f"{int(v):,}".replace(",", ".")
    except Exception:
        return str(v)

def _fmt_pct_pt(v):
    try:
        return (f"{float(v):.2f}%").replace(".", ",")
    except Exception:
        return str(v)

def _fmt_pp_pt(v):
    try:
        return (f"{float(v):+.2f} p.p.").replace(".", ",")
    except Exception:
        return str(v)

def _get_cancel_date_col(df: pd.DataFrame, include_emission_fallback: bool = True):
    """Retorna a coluna de data mais adequada para cancelamentos.

    Prioridade padrão do dashboard:
    1) DATA_CANCELADO
    2) DATA_CANCEL
    3) DATA_EMISSÃO / DATA_EMISSAO (fallback)
    """
    if df is None or not isinstance(df, pd.DataFrame):
        return None

    candidates = ["DATA_CANCELADO", "DATA_CANCEL"]
    if include_emission_fallback:
        candidates.extend(["DATA_EMISSÃO", "DATA_EMISSAO"])

    for col in candidates:
        if col in df.columns:
            return col
    return None

def _get_cancel_month_col(df: pd.DataFrame):
    """Retorna a coluna mensal principal para cancelamentos."""
    if df is None or not isinstance(df, pd.DataFrame):
        return None
    for col in ["MÊS_CANCELAMENTO", "MÊS"]:
        if col in df.columns:
            return col
    return None

# =============================================================
# Helpers — EDI (placas base + correlacionadas)
# Regras (base):
# - ARMABPS  <- ARMABP1/2/3...
# - ARMAFLB  <- ARMAFL1/2/3...
# - ARMAVIT  <- ARMAVT1/2/3... e ARMAVIT
# - ARMAJMF  <- ARMAJM1/2/3... e ARMAJMF
# - LOGDHL1  <- LOGDHL2/3/4...
# =============================================================

def _to_num_br(s: pd.Series) -> pd.Series:
    """Converte números no padrão PT-BR (1.234,56) e também lida com milhares com ponto (10.343)."""
    if s is None:
        return pd.Series(dtype=float)
    try:
        if pd.api.types.is_numeric_dtype(s):
            return pd.to_numeric(s, errors="coerce")
    except Exception:
        pass
    # Limpa símbolos de moeda e quaisquer caracteres não numéricos relevantes
    x = s.astype(str).fillna("").str.strip()
    x = x.str.replace(r"[^0-9,\.\-]", "", regex=True)
    # Se tiver vírgula, assume vírgula como decimal e ponto como milhar
    has_comma = x.str.contains(",", na=False)
    x2 = x.copy()
    x2.loc[has_comma] = x2.loc[has_comma].str.replace(".", "", regex=False).str.replace(",", ".", regex=False)
    # Se NÃO tiver vírgula, decide se ponto é milhar (###.###) ou decimal (##.##)
    thousands_pat = x2.str.match(r"^\d{1,3}(\.\d{3})+$", na=False)
    x2.loc[~has_comma & thousands_pat] = x2.loc[~has_comma & thousands_pat].str.replace(".", "", regex=False)
    return pd.to_numeric(x2, errors="coerce")

def _edi_group_from_norm(pl_norm: str) -> str:
    s = "" if pl_norm is None else str(pl_norm).upper()
    if s.startswith("ARMABP"):
        return "ARMABPS"
    if s.startswith("ARMAFL"):
        return "ARMAFLB"
    # ARMAFAV (base) <- ARMAFV1/2/3/4 (correlacionadas)
    # Ex.: ARMAFV1, ARMAFV2, ARMAFV3, ARMAFV4 devem aparecer como ARMAFAV no modo EDI
    if re.match(r"^ARMAFV[1-4]$", s):
        return "ARMAFAV"
    if s.startswith("ARMAVT") or s.startswith("ARMAVIT"):
        return "ARMAVIT"
    if s.startswith("ARMAJM"):
        return "ARMAJMF"
    if s.startswith("LOGDHL"):
        return "LOGDHL1"
    return s

def _is_edi_from_norm(pl_norm: str) -> bool:
    s = "" if pl_norm is None else str(pl_norm).upper()
    return (
        s.startswith("ARMABP")
        or s.startswith("ARMAFL")
        or s.startswith("ARMAFV")
        or s.startswith("ARMAFAV")
        or s.startswith("ARMAVT")
        or s.startswith("ARMAVIT")
        or s.startswith("ARMAJM")
        or s.startswith("LOGDHL")
    )

# =============================================================
# Helpers — Placas correlacionadas (NÃO EDI)
# Regras (base):
# - ARMAMPS <- ARMAMP1/2/3... e ARMAMPS
# =============================================================
def _nonedi_group_from_norm(pl_norm: str) -> str:
    s = "" if pl_norm is None else str(pl_norm).upper()
    if s.startswith("ARMAMP"):
        return "ARMAMPS"
    return s

# Normalização para busca textual (ignora acento, maiúsculas e pontuação)
def _norm_text_search(s: str) -> str:
    s = "" if s is None else str(s)
    s = "".join(c for c in unicodedata.normalize("NFKD", s) if not unicodedata.combining(c))
    s = s.lower()
    s = re.sub(r"[^a-z0-9]+", " ", s)
    s = re.sub(r"\s+", " ", s).strip()
    return s

# -------------------------------------------------------------
# Filtro de texto para Observação (reutilizável em "Controles de Ocorrências")
# - Ignora acentos/maiúsculas/pontuação (via _norm_text_search)
# - Se a busca contém "nr"/"nrs" => considera QUALQUER ocorrência de NR na observação
#   (NR INVALIDO/INVALIDA, NRS INVALIDAS, NR ILEGIVEL etc.)
# - Caso contrário => match por tokens (AND)
# -------------------------------------------------------------
def _apply_obs_query_filter(df: pd.DataFrame, obs_col: str, query: str) -> pd.DataFrame:
    if df is None or df.empty:
        return df
    if (obs_col is None) or (obs_col not in df.columns):
        return df.iloc[0:0]

    qn = _norm_text_search(query)
    toks = [t for t in qn.split() if t]
    if not toks:
        return df

    obs_norm = df[obs_col].fillna("").astype(str).map(_norm_text_search)

    is_nr_query = ("nr" in toks) or ("nrs" in toks) or qn.startswith("nr") or qn.startswith("nrs")
    if is_nr_query:
        return df[obs_norm.str.contains(r"\bnr", regex=True, na=False)]

    mask = pd.Series(True, index=df.index)
    for t in toks:
        mask &= obs_norm.str.contains(re.escape(t), na=False)
    return df[mask]

# =============================================================
# Helpers (Semana do mês / Dia da semana) - usados no Ranking
# - Semana do mês fixa em 4 faixas:
#   1ª: 01-07 | 2ª: 08-14 | 3ª: 15-21 | 4ª: 22-fim
# =============================================================
DOW_PT_TO_NUM = {
    "Segunda": 0,
    "Terça": 1,
    "Quarta": 2,
    "Quinta": 3,
    "Sexta": 4,
    "Sábado": 5,
    "Domingo": 6,
}

def _week_1to4(dt: pd.Series) -> pd.Series:
    """Retorna a semana do mês (1-4) para uma série datetime."""
    day = dt.dt.day
    wk = ((day - 1) // 7) + 1
    return wk.clip(upper=4)

def _apply_week_dow_filters(df: pd.DataFrame, dt_col: str, semana_sel: str, dow_sel: str) -> pd.DataFrame:
    """Aplica filtros de semana (1-4) e dia da semana (PT) em um DataFrame, se possível."""
    if df is None or df.empty:
        return df
    if (dt_col is None) or (dt_col not in df.columns):
        return df

    out = df.copy()
    out[dt_col] = pd.to_datetime(out[dt_col], errors="coerce", dayfirst=True)
    out = out[out[dt_col].notna()]

    # Semana (1-4)
    if semana_sel and semana_sel != "Todas":
        wk_map = {"1ª Semana": 1, "2ª Semana": 2, "3ª Semana": 3, "4ª Semana": 4}
        wk = wk_map.get(semana_sel)
        if wk is not None:
            out = out[_week_1to4(out[dt_col]) == wk]

    # Dia da semana
    if dow_sel and dow_sel != "Todos":
        dow = DOW_PT_TO_NUM.get(dow_sel)
        if dow is not None:
            out = out[out[dt_col].dt.weekday == dow]

    return out

# ✅ NOVA FUNÇÃO PARA EMBUTIR A IMAGEM
def get_image_as_base64(path):
    """Lê um arquivo de imagem e o converte para o formato Base64."""
    if not os.path.exists(path):
        return None
    with open(path, "rb") as image_file:
        return base64.b64encode(image_file.read()).decode()


