def _avatar_usuario_data_uri(nome_usuario: str) -> str:
    """Retorna o data URI principal do avatar do usuário, se existir; caso contrário, string vazia."""
    try:
        chave = normalizar_usuario(nome_usuario)
    except Exception:
        try:
            chave = str(nome_usuario).strip().upper()
        except Exception:
            chave = ""
    if not chave:
        return ""
    return AVATAR_USUARIOS_DATA_URI.get(chave, "")

def _avatar_usuario_square_data_uri(nome_usuario: str) -> str:
    """Retorna o data URI quadrado do avatar do usuário, se existir; caso contrário, string vazia."""
    try:
        chave = normalizar_usuario(nome_usuario)
    except Exception:
        try:
            chave = str(nome_usuario).strip().upper()
        except Exception:
            chave = ""
    if not chave:
        return ""
    return AVATAR_USUARIOS_SQUARE_DATA_URI.get(chave, "")


