_MOTORISTA_STOP = {"-", "—", "–"}

def motorista_alias_canonico(apelido: str) -> str:
    """Normaliza apelidos parecidos com a chave do de-para (ex.: OJMARTIN -> JOAOMART)."""
    a = "" if apelido is None else str(apelido).strip().upper()
    a = re.sub(r"\s+", "", a)
    if not a:
        return ""
    if a in MOTORISTA_DEPARA:
        return a

    keys = list(MOTORISTA_DEPARA.keys())
    a_alpha = re.sub(r"[^A-Z]", "", a)

    # 1) prefixo / chave contida
    pref = [k for k in keys if k.startswith(a) or a.startswith(k)]
    if pref:
        return sorted(pref, key=lambda k: (abs(len(k) - len(a)), k))[0]

    # 2) candidatos por prefixo/sufixo textual
    scored = []
    for k in keys:
        k_alpha = re.sub(r"[^A-Z]", "", k)
        score = 0
        if a_alpha and k_alpha.startswith(a_alpha[:4]):
            score += 3
        if len(a_alpha) >= 3 and k_alpha.endswith(a_alpha[-3:]):
            score += 2
        if len(a_alpha) >= 5 and a_alpha[:5] == k_alpha[:5]:
            score += 2
        if score > 0:
            scored.append((score, k))

    if scored:
        ordered = [k for _, k in sorted(scored, key=lambda x: (-x[0], abs(len(x[1]) - len(a)), x[1]))]
        close = get_close_matches(a, ordered, n=1, cutoff=0.45)
        if close:
            return close[0]
        return ordered[0]

    # 3) fallback geral por similaridade
    close = get_close_matches(a, keys, n=1, cutoff=0.72)
    return close[0] if close else a

def motorista_info(apelido: str) -> dict:
    """APELIDO -> {'COD': '0015', 'NOME': 'NOME COMPLETO'}"""
    a = "" if apelido is None else str(apelido).strip().upper()
    a = motorista_alias_canonico(a)
    if not a:
        return {"COD": "", "NOME": ""}

    v = MOTORISTA_DEPARA.get(a)

    if isinstance(v, dict):
        cod = "" if v.get("COD") is None else str(v.get("COD")).strip()
        nome = "" if v.get("NOME") is None else str(v.get("NOME")).strip()
        return {"COD": cod, "NOME": nome}

    # fallback (se sobrar algum legado APELIDO -> "NOME")
    if isinstance(v, str):
        return {"COD": "", "NOME": v.strip()}

    return {"COD": "", "NOME": a}

def motorista_nome_completo(apelido: str) -> str:
    return motorista_info(apelido).get("NOME", "") or ""

def motorista_codigo3(apelido: str) -> str:
    """Formata COD para 3 dígitos: 0144 -> 144"""
    cod = motorista_info(apelido).get("COD", "") or ""
    cod_digits = re.sub(r"\D", "", str(cod))
    if not cod_digits:
        return ""
    cod_digits = cod_digits.zfill(4)
    return cod_digits[-3:]

def motorista_primeiro_nome(apelido: str) -> str:
    full = motorista_nome_completo(apelido)
    if not full:
        # fallback: usa o próprio apelido
        return ("" if apelido is None else str(apelido).strip().upper())

    toks = [t for t in str(full).replace("—"," ").replace("–"," ").split() if t and t not in _MOTORISTA_STOP]
    if not toks:
        return ("" if apelido is None else str(apelido).strip().upper())

    # caso especial: "KM - CONFERENTE ..."
    if toks[0] == "KM":
        toks = toks[1:]
        if toks and toks[0] in ["-", "—", "–"]:
            toks = toks[1:]

    return toks[0] if toks else "KM"

def motorista_label(apelido: str) -> str:
    first = motorista_primeiro_nome(apelido)
    cod3 = motorista_codigo3(apelido)
    if not first:
        return ""
    return f"👤{first} - {cod3}" if cod3 else f"👤{first}"


