            taxa_cancel_prod = (float(total_cancel_prod) / float(total_emissoes_periodo) * 100.0) if float(total_emissoes_periodo) > 0 else 0.0

            def _get_tipo_col_prod(df_in: pd.DataFrame):
                if df_in is None or df_in.empty:
                    return None
                try:
                    for c in df_in.columns:
                        nk = _norm_key(c)
                        if ("tipodoc" in nk) or ("tipo" in nk and "doc" in nk) or (nk == "tipo"):
                            return c
                except Exception:
                    pass
                return _find_col_contains(df_in, "TIPO")

            def _count_tipo_prod(df_in: pd.DataFrame, alvo: str) -> int:
                if df_in is None or df_in.empty:
                    return 0
                _tc = _get_tipo_col_prod(df_in)
                if (_tc is None) or (_tc not in df_in.columns):
                    return 0
                tmp = df_in.copy()
                tmp["_TIPO_CAT_"] = tmp[_tc].apply(categoria_tipo_documento)
                if "CTRC_EMITIDO" in tmp.columns:
                    return int(pd.to_numeric(tmp.loc[tmp["_TIPO_CAT_"] == alvo, "CTRC_EMITIDO"], errors="coerce").fillna(0).sum())
                return int((tmp["_TIPO_CAT_"] == alvo).sum())

            def _top_usuario_tipo_prod(df_in: pd.DataFrame, alvo: str):
                if df_in is None or df_in.empty:
                    return ("N/D", 0, "N/D")
                _tc = _get_tipo_col_prod(df_in)
                if (_tc is None) or (_tc not in df_in.columns):
                    return ("N/D", 0, "N/D")
                _uc = "USUÁRIO" if "USUÁRIO" in df_in.columns else (_find_col_contains(df_in, "usuario") or _find_col_contains(df_in, "usuário"))
                if (_uc is None) or (_uc not in df_in.columns):
                    return ("N/D", 0, "N/D")

                tmp = df_in.copy()
                tmp["_TIPO_CAT_"] = tmp[_tc].apply(categoria_tipo_documento)
                tmp = tmp[tmp["_TIPO_CAT_"] == alvo].copy()
                if tmp.empty:
                    return ("N/D", 0, "N/D")

                tmp["_USR_"] = tmp[_uc].fillna("").astype(str).str.strip()
                tmp = tmp[tmp["_USR_"] != ""]
                if tmp.empty:
                    return ("N/D", 0, "N/D")

                if "CTRC_EMITIDO" in tmp.columns:
                    serie = pd.to_numeric(tmp["CTRC_EMITIDO"], errors="coerce").fillna(0)
                    grp = tmp.assign(_QTD_=serie).groupby("_USR_")["_QTD_"].sum().sort_values(ascending=False)
                else:
                    grp = tmp.groupby("_USR_").size().sort_values(ascending=False)
                if grp.empty:
                    return ("N/D", 0, "N/D")

                nome_full = str(grp.index[0]).strip() or "N/D"
                qtd = int(float(grp.iloc[0]))
                nome_card = _first_words(nome_full, n=2, max_len=14).upper() if nome_full != "N/D" else "N/D"
                return (nome_card, qtd, nome_full)

            def _count_nr_invalid_prod(_df: pd.DataFrame, _raw_df: pd.DataFrame | None = None) -> int:
                def _count_from_df(_base: pd.DataFrame) -> int:
                    if (_base is None) or (not isinstance(_base, pd.DataFrame)) or _base.empty:
                        return 0
                    _obs_col = (
                        _find_col_contains(_base, "observ")
                        or _find_col_contains(_base, "observacao")
                        or next((c for c in _base.columns if "observ" in _norm_key(c)), None)
                    )
                    if (_obs_col is None) or (_obs_col not in _base.columns):
                        return 0
                    try:
                        return int(len(_apply_obs_query_filter(_base, _obs_col, "NR")))
                    except Exception:
                        _obs_norm = _base[_obs_col].fillna("").astype(str).map(_norm_text_search)
                        return int(_obs_norm.str.contains(r"\bnr", regex=True, na=False).sum())

                # Prioriza a base bruta já filtrada da aba para manter o mesmo total do
                # controle de ocorrências e evitar divergência como 18 x 20.
                _cnt_raw = _count_from_df(_raw_df)
                if _cnt_raw > 0:
                    return _cnt_raw
                return _count_from_df(_df)

            top_user_normal, top_user_normal_qtd, top_user_normal_full = _top_usuario_tipo_prod(df_tab3, "NORMAL")
