            st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)

            # --- aplica filtros de Tipo/Placa também no gráfico de ranking (barras) ---
            df_rank_base = df_emissoes_ranking.copy()

            # ------------------------------------------------------------
