            # ✅ Guarda base SEM filtro de tipo (para comparar NORMAL x REDESPACHO no gráfico)
            df_rank_base_alltypes = df_rank_base.copy()

            # Seleção de Tipo de Emissões (barra no lugar de TODOS/TOP 5/10/20)
            tipo_emissao_bar = st.session_state.get("ranking_tipo_emissao_sel", "Todos")

            # ✅ Opções do "Tipo de Emissão" puxadas da coluna "Tipo do Documento"
