                        def _user_initials_local(name: str) -> str:
                            try:
                                toks = [t for t in str(name).replace("_", " ").split() if t.strip()]
                                if not toks:
                                    return "--"
                                if len(toks) == 1:
                                    return toks[0][:2].upper()
                                return (toks[0][0] + toks[1][0]).upper()
                            except Exception:
                                return "--"

                        def _turno_norm_local(v) -> str:
                            try:
                                s = str(v).strip().upper()
                            except Exception:
                                return "MISTO"
                            if not s:
                                return "MISTO"
                            if "NOITE" in s or "NOTUR" in s:
                                return "NOITE"
                            if "DIA" in s or "DIUR" in s:
                                return "DIA"
                            return "MISTO"
                        def _preview_fmt_dur_hm(_sec: int) -> str:
                            try:
                                s = int(max(0, _sec))
                            except Exception:
                                s = 0
                            h = s // 3600
                            m = (s % 3600) // 60
                            return f"{h:02d}h {m:02d}m"

                        def _preview_window_sec_from_dtseries(_s: pd.Series) -> int:
                            try:
                                s = pd.to_datetime(_s, errors="coerce", dayfirst=True).dropna()
                            except Exception:
                                return 0
                            if len(s) <= 1:
                                return 0
                            mins = sorted(set(int(v) for v in (s.dt.hour * 60 + s.dt.minute).dropna().tolist()))
                            if len(mins) <= 1:
                                return 0
                            gaps = []
                            for i in range(len(mins) - 1):
                                gaps.append((mins[i + 1] - mins[i], i))
                            gaps.append((mins[0] + 1440 - mins[-1], len(mins) - 1))
                            gap_max, _ = max(gaps, key=lambda x: x[0])
                            dur_min = max(0, 1440 - int(gap_max))
                            return int(dur_min) * 60

