                                            total_peso_u = float(_to_num_br(df_u_quick[_peso_col_det]).sum()) if (_peso_col_det and (_peso_col_det in df_u_quick.columns) and (not df_u_quick.empty)) else 0.0
                                            total_cub_u = float(_to_num_br(df_u_quick[_cub_col_det]).sum()) if (_cub_col_det and (_cub_col_det in df_u_quick.columns) and (not df_u_quick.empty)) else 0.0

