                                            red_share_u = (float(red_u) / total_tipo_u * 100.0) if total_tipo_u > 0 else 0.0
                                        
                                        
                                            def _fmt_float_pt_local(v: float, dec: int = 2) -> str:
                                                try:
                                                    s = f"{float(v):,.{dec}f}"
                                                    return s.replace(",", "X").replace(".", ",").replace("X", ".")
                                                except Exception:
                                                    return "0,00"

                                            def _fmt_dur_hm(_sec: int) -> str:
                                                try:
                                                    s = int(max(0, _sec))
                                                except Exception:
                                                    s = 0
                                                h = s // 3600
                                                m = (s % 3600) // 60
                                                if h > 0:
                                                    return f"{h:02d}h {m:02d}m"
                                                return f"00h {m:02d}m"

                                            def _fmt_hours_1dec(_h: float) -> str:
                                                try:
                                                    return str(f"{float(_h):.1f}").replace(".", ",")
                                                except Exception:
                                                    return "0,0"

                                            def _pct_delta(_cur, _prev) -> float:
                                                try:
                                                    _cur = float(_cur)
                                                    _prev = float(_prev)
                                                except Exception:
                                                    return 0.0
                                                if _prev == 0:
                                                    return 0.0 if _cur == 0 else 100.0
                                                return (_cur - _prev) / _prev * 100.0

                                            def _delta_text(_cur, _prev, *, label: str = "vs mês ant.", good_when: str = "up"):
                                                _pct = _pct_delta(_cur, _prev)
                                                _arrow = "▲" if _pct > 0 else ("▼" if _pct < 0 else "•")
                                                _pct_s = str(f"{abs(_pct):.1f}").replace(".", ",")
                                                _kind = None
                                                if _pct != 0:
                                                    if good_when == "down":
                                                        _kind = "good" if _pct < 0 else "bad"
                                                    else:
                                                        _kind = "good" if _pct > 0 else "bad"
                                                return f"{_arrow} {_pct_s}% <span>{label}</span>", _kind

                                            # ✅ Mini header (estilo da 1ª imagem) — resumo do usuário selecionado
