                                                        out_cols["Conferente de Coleta"] = df_p[conf_col_raw] if (conf_col_raw is not None and conf_col_raw in df_p.columns) else ""
                                                        out_cols["Observacao"] = df_p[obs_col_raw] if (obs_col_raw is not None and obs_col_raw in df_p.columns) else ""
                                                        out_cols["Quantidade de Volumes"] = df_p[vol_col_raw] if (vol_col_raw is not None and vol_col_raw in df_p.columns) else ""
                                                        out_cols["Peso Real KG"] = df_p[peso_col_raw] if (peso_col_raw is not None and peso_col_raw in df_p.columns) else ""
                                                        out_cols["Cubagem m³"] = df_p[cub_col_raw] if (cub_col_raw is not None and cub_col_raw in df_p.columns) else ""
                                                        out_cols["Frete R$"] = df_p[frete_col_raw] if (frete_col_raw is not None and frete_col_raw in df_p.columns) else ""

