            if (placa_col is not None) and (not df_user_em.empty):
                df_user_em["_PLACA_RAW"] = df_user_em[placa_col].fillna("").astype(str).str.strip().str.upper()
                df_user_em["_PLACA_RAW"] = df_user_em["_PLACA_RAW"].replace({"": "SEM PLACA", "NAN": "SEM PLACA", "NONE": "SEM PLACA"})
                df_user_em["_PLACA_NORM"] = df_user_em["_PLACA_RAW"].str.replace(r"[^A-Z0-9]", "", regex=True)

