            # --------------------
            # Tab 3 — Evolução
            # --------------------
            with tab_ev:
                st.markdown("#### 📈 Evolução de Emissões no Tempo")
                if (df_user_em is None) or (df_user_em.empty):
                    st.info("Sem dados no período/filtros atuais para gerar este gráfico.")
                else:
                    # --- Detecção robusta de coluna de data (preferência: emissão) ---
                    def _norm_colname(_s: str) -> str:
                        try:
                            _s = str(_s)
                        except Exception:
                            _s = ""
                        _s = _s.strip().lower()
                        _s = unicodedata.normalize("NFKD", _s).encode("ascii", "ignore").decode("ascii")
                        _s = re.sub(r"\s+", " ", _s)
                        _s = re.sub(r"[^a-z0-9_ ]+", "", _s)
                        return _s

                    def _score_date_col(_col: str) -> int:
                        n = _norm_colname(_col)
                        score = 0
                        if "data" in n or "date" in n:
                            score += 4
                        if n.startswith("dt") or " dt " in f" {n} ":
                            score += 3
                        if "emiss" in n or "emissao" in n:
                            score += 5
                        # penalidades para evitar datas que não são de emissão
                        if "cancel" in n:
                            score -= 8
                        if "ocorr" in n:
                            score -= 4
                        if "entrega" in n or "previs" in n:
                            score -= 3
                        return score

                    _cand = []
                    for _c in df_user_em.columns:
                        sc = _score_date_col(_c)
                        if sc > 0:
                            _cand.append((_c, sc))
                    _cand = sorted(_cand, key=lambda x: x[1], reverse=True)
                    _date_col = _cand[0][0] if len(_cand) else None

                    if (_date_col is None) or (_date_col not in df_user_em.columns):
                        st.info("Não encontrei uma coluna de data para montar a evolução (ex.: DATA, DT_EMISSAO, DATA EMISSÃO / Data de Emissao).")
                        with st.expander("🔎 Ver colunas disponíveis"):
                            st.write(list(df_user_em.columns))
                    else:
                        # Permite ajustar manualmente se houver mais de uma candidata
                        if len(_cand) > 1:
                            with st.expander("⚙️ Configurar coluna de data (opcional)"):
                                _opts = [c for c, _s in _cand]
