                _corr_key_auto = _corr_raw_auto.str.lower()
                _corr_nome_auto = _corr_key_auto.map(lambda x: MAPEAMENTO_USUARIOS.get(str(x), {}).get("USUÁRIO", ""))
                df_work["_RESP_CORR_NOME"] = np.where((_corr_nome_auto.notna()) & (_corr_nome_auto != ""), _corr_nome_auto, _corr_raw_auto)
