                stats["_LABEL_FULL"] = stats[group_col].astype(str)

                def _short_lab_ms(s: str, max_len: int = 42) -> str:
                    s = ("" if s is None else str(s)).strip()
                    return (s[:max_len] + "…") if len(s) > (max_len + 1) else s

                stats["_LABEL"] = stats["_LABEL_FULL"].apply(_short_lab_ms)
