                                        # KPIs rápidos
                                        _tot_c = int(df_mot_tbl["Cancelamentos"].sum()) if "Cancelamentos" in df_mot_tbl.columns else 0
                                        _uniq = int(df_mot_tbl["Motivo"].nunique()) if "Motivo" in df_mot_tbl.columns else 0
