                                            def _cat_nr(obs: str) -> str:
                                                s = _norm_text_search(obs)
                                                if not s:
                                                    return "N/D"
                                                if "ilegiv" in s:
                                                    return "NR ILEGÍVEL"
                                                if "inval" in s:
                                                    return "NR INVÁLIDA"
                                                if "seguindo com" in s:
                                                    return "SEGUINDO COM..."
                                                if ("sem nr" in s) or ("nao" in s and "encontr" in s):
                                                    return "NR NÃO ENCONTRADO"
                                                return "OUTROS (NR)"

                                            if (obs_col_raw is not None) and (obs_col_raw in df_m.columns):
                                                _o = df_m[obs_col_raw].fillna("").astype(str).str.strip()
                                                df_cat = pd.DataFrame({"Categoria": _o.map(_cat_nr)})
                                                _catc = df_cat["Categoria"].value_counts().reset_index()
                                                _catc.columns = ["Categoria", "Ocorrências"]
